{
  "name": "set_window_position",
  "description": "调整指定车窗的开合位置。仅在车速低于阈值且驾驶模式允许时可用。",
  "parameters": {
    "type": "object",
    "properties": {
      "window_id": {
        "type": "string",
        "enum": ["front_left", "front_right", "rear_left", "rear_right", "sunroof"],
        "description": "要控制的车窗标识"
      },
      "position_percent": {
        "type": "integer",
        "minimum": 0,
        "maximum": 100,
        "description": "开合百分比，0=完全关闭，100=完全打开"
      },
      "speed": {
        "type": "string",
        "enum": ["slow", "normal", "fast"],
        "default": "normal"
      }
    },
    "required": ["window_id", "position_percent"],
    "additionalProperties": false
  },
  "returns": {
    "type": "object",
    "properties": {
      "success": {"type": "boolean"},
      "actual_position": {"type": "integer"},
      "error_code": {"type": "string"}
    }
  }
}
